1	package service
2	
3	import (
4		"context"
5		"encoding/json"
6		"fmt"
7		"strings"
8	
9		"github.com/google/uuid"
10		"github.com/ledgermint/platform/internal/dto"
11		"github.com/ledgermint/platform/internal/model"
12		"github.com/ledgermint/platform/internal/store"
13	)
14	
15	type NotificationService struct {
16		notifStore *store.NotificationStore
17	}
18	
19	func NewNotificationService(ns *store.NotificationStore) *NotificationService {
20		return &NotificationService{notifStore: ns}
21	}
22	
23	func (s *NotificationService) Send(ctx context.Context, userID uuid.UUID, templateSlug string, paramsJSON json.RawMessage) error {
24		// Check user preferences
25		prefs, err := s.notifStore.GetPreferences(ctx, userID)
26		if err != nil {
27			return fmt.Errorf("get preferences: %w", err)
28		}
29	
30		var prefMap map[string]bool
31		if err := json.Unmarshal(prefs.Preferences, &prefMap); err != nil {
32			prefMap = make(map[string]bool)
33		}
34		if enabled, exists := prefMap[templateSlug]; exists && !enabled {
35			return nil // User opted out
36		}
37	
38		template, err := s.notifStore.GetTemplateBySlug(ctx, templateSlug)
39		if err != nil {
40			return fmt.Errorf("get template: %w", err)
41		}
42		if template == nil {
43			return fmt.Errorf("template not found: %s", templateSlug)
44		}
45	
46		// Render template
47		var params map[string]string
48		if err := json.Unmarshal(paramsJSON, &params); err != nil {
49			params = make(map[string]string)
50		}
51	
52		title := renderTemplate(template.TitleTemplate, params)
53		body := renderTemplate(template.BodyTemplate, params)
54	
55		notif := &model.Notification{
56			UserID:        userID,
57			TemplateID:    template.ID,
58			Params:        paramsJSON,
59			RenderedTitle: title,
60			RenderedBody:  body,
61			Status:        "pending",
62		}
63	
64		if err := s.notifStore.Create(ctx, notif); err != nil {
65			return fmt.Errorf("create notification: %w", err)
66		}
67		return nil
68	}
69	
70	func (s *NotificationService) List(ctx context.Context, userID uuid.UUID, unreadOnly bool, page, pageSize int) ([]model.Notification, int, error) {
71		return s.notifStore.ListByUser(ctx, userID, unreadOnly, page, pageSize)
72	}
73	
74	func (s *NotificationService) MarkRead(ctx context.Context, id, userID uuid.UUID) error {
75		notif, err := s.notifStore.GetByID(ctx, id)
76		if err != nil {
77			return err
78		}
79		if notif == nil {
80			return dto.ErrNotFound
81		}
82		if notif.UserID != userID {
83			return dto.ErrForbidden
84		}
85		return s.notifStore.MarkRead(ctx, id)
86	}
87	
88	func (s *NotificationService) MarkAllRead(ctx context.Context, userID uuid.UUID) error {
89		return s.notifStore.MarkAllRead(ctx, userID)
90	}
91	
92	func (s *NotificationService) CountUnread(ctx context.Context, userID uuid.UUID) (int, error) {
93		return s.notifStore.CountUnread(ctx, userID)
94	}
95	
96	func (s *NotificationService) Retry(ctx context.Context, id, userID uuid.UUID) error {
97		notif, err := s.notifStore.GetByID(ctx, id)
98		if err != nil {
99			return err
100		}
101		if notif == nil {
102			return dto.ErrNotFound
103		}
104		if notif.UserID != userID {
105			return dto.ErrForbidden
106		}
107		if notif.Status != "failed" && notif.Status != "permanently_failed" {
108			return fmt.Errorf("%w: notification is not in a failed state", dto.ErrValidation)
109		}
110		// Manual retry resets to pending so the worker picks it up on the next tick.
111		return s.notifStore.ResetToPending(ctx, id)
112	}
113	
114	func (s *NotificationService) GetPreferences(ctx context.Context, userID uuid.UUID) (*model.NotificationPreferences, error) {
115		return s.notifStore.GetPreferences(ctx, userID)
116	}
117	
118	func (s *NotificationService) UpdatePreferences(ctx context.Context, userID uuid.UUID, prefs map[string]bool) error {
119		data, err := json.Marshal(prefs)
120		if err != nil {
121			return fmt.Errorf("marshal preferences: %w", err)
122		}
123		return s.notifStore.UpsertPreferences(ctx, userID, data)
124	}
125	
126	func (s *NotificationService) ListTemplates(ctx context.Context) ([]model.NotificationTemplate, error) {
127		return s.notifStore.ListTemplates(ctx)
128	}
129	
130	func renderTemplate(tmpl string, params map[string]string) string {
131		result := tmpl
132		for k, v := range params {
133			result = strings.ReplaceAll(result, "{{."+k+"}}", v)
134		}
135		return result
136	}
