1	package service
2	
3	import (
4		"context"
5		"fmt"
6	
7		"github.com/google/uuid"
8		"github.com/ledgermint/platform/internal/dto"
9		"github.com/ledgermint/platform/internal/model"
10		"github.com/ledgermint/platform/internal/store"
11	)
12	
13	const MaxAttachmentSize = 10 * 1024 * 1024 // 10 MB
14	
15	type MessageService struct {
16		messageStore *store.MessageStore
17		orderStore   *store.OrderStore
18	}
19	
20	func NewMessageService(ms *store.MessageStore, os *store.OrderStore) *MessageService {
21		return &MessageService{messageStore: ms, orderStore: os}
22	}
23	
24	func (s *MessageService) Send(ctx context.Context, orderID uuid.UUID, senderID uuid.UUID, body string,
25		attachmentPath string, attachmentSize int, attachmentMime string) (*model.Message, error) {
26	
27		// Verify order exists and sender is buyer or seller
28		order, err := s.orderStore.GetByID(ctx, orderID)
29		if err != nil {
30			return nil, err
31		}
32		if order == nil {
33			return nil, dto.ErrNotFound
34		}
35		if order.BuyerID != senderID && order.SellerID != senderID {
36			return nil, dto.ErrForbidden
37		}
38	
39		// Server-side attachment size check
40		if attachmentSize > MaxAttachmentSize {
41			return nil, dto.ErrAttachmentTooLarge
42		}
43	
44		msg := &model.Message{
45			OrderID:        orderID,
46			SenderID:       senderID,
47			Body:           body,
48			AttachmentPath: attachmentPath,
49			AttachmentSize: attachmentSize,
50			AttachmentMime: attachmentMime,
51		}
52	
53		if err := s.messageStore.Create(ctx, msg); err != nil {
54			return nil, fmt.Errorf("create message: %w", err)
55		}
56		return msg, nil
57	}
58	
59	func (s *MessageService) ListByOrder(ctx context.Context, orderID, userID uuid.UUID, page, pageSize int) ([]model.Message, int, error) {
60		// Verify user is participant
61		order, err := s.orderStore.GetByID(ctx, orderID)
62		if err != nil {
63			return nil, 0, err
64		}
65		if order == nil {
66			return nil, 0, dto.ErrNotFound
67		}
68		if order.BuyerID != userID && order.SellerID != userID {
69			return nil, 0, dto.ErrForbidden
70		}
71	
72		return s.messageStore.ListByOrder(ctx, orderID, page, pageSize)
73	}
