1	package handler
2	
3	import (
4		"net/http"
5	
6		"github.com/google/uuid"
7		"github.com/labstack/echo/v4"
8		"github.com/ledgermint/platform/internal/dto"
9		"github.com/ledgermint/platform/internal/middleware"
10		"github.com/ledgermint/platform/internal/model"
11		"github.com/ledgermint/platform/internal/service"
12		"github.com/ledgermint/platform/internal/store"
13	)
14	
15	type OrderHandler struct {
16		orderService *service.OrderService
17		auditStore   *store.AuditStore
18	}
19	
20	func NewOrderHandler(os *service.OrderService, audit *store.AuditStore) *OrderHandler {
21		return &OrderHandler{orderService: os, auditStore: audit}
22	}
23	
24	func (h *OrderHandler) Create(c echo.Context) error {
25		var req dto.CreateOrderRequest
26		if err := bindAndValidate(c, &req); err != nil {
27			return err
28		}
29	
30		idempotencyKey := c.Request().Header.Get("Idempotency-Key")
31		if idempotencyKey == "" {
32			return errorResponse(c, http.StatusBadRequest, dto.CodeValidation, "Idempotency-Key header is required")
33		}
34	
35		buyerID, err := uuid.Parse(middleware.GetUserID(c))
36		if err != nil {
37			return errorResponse(c, http.StatusUnauthorized, dto.CodeUnauthorized, "invalid user")
38		}
39	
40		order, err := h.orderService.Create(c.Request().Context(), req, buyerID, idempotencyKey)
41		if err != nil {
42			return mapError(c, err)
43		}
44		if h.auditStore != nil {
45			h.auditStore.LogEvent(c.Request().Context(), &buyerID, model.AuditActionOrderCreate, "order", &order.ID,
46				map[string]interface{}{"collectible_id": req.CollectibleID.String()}, c.RealIP())
47		}
48		return c.JSON(http.StatusCreated, order)
49	}
50	
51	func (h *OrderHandler) Get(c echo.Context) error {
52		id, err := uuid.Parse(c.Param("id"))
53		if err != nil {
54			return errorResponse(c, http.StatusBadRequest, dto.CodeValidation, "invalid order ID")
55		}
56	
57		actorID, err := uuid.Parse(middleware.GetUserID(c))
58		if err != nil {
59			return errorResponse(c, http.StatusUnauthorized, dto.CodeUnauthorized, "invalid user")
60		}
61	
62		order, err := h.orderService.GetByID(c.Request().Context(), id, actorID)
63		if err != nil {
64			return mapError(c, err)
65		}
66		return c.JSON(http.StatusOK, order)
67	}
68	
69	func (h *OrderHandler) List(c echo.Context) error {
70		userID, err := uuid.Parse(middleware.GetUserID(c))
71		if err != nil {
72			return errorResponse(c, http.StatusUnauthorized, dto.CodeUnauthorized, "invalid user")
73		}
74	
75		page, pageSize := pagination(c)
76		role := c.QueryParam("role")
77	
78		var orders []model.Order
79		var total int
80	
81		if role == "seller" {
