247	// resolveABVariant builds a comma-separated ab_variant tag for all running tests.
248	// Returns "" if there are no running tests or the user is nil.
249	func resolveABVariant(analyticsStore *store.AnalyticsStore, userID *uuid.UUID) string {
250		if userID == nil || analyticsStore == nil {
251			return ""
252		}
253		tests, _ := analyticsStore.ListRunningABTests(context.Background())
254		if len(tests) == 0 {
255			return ""
256		}
257		parts := make([]string, 0, len(tests))
258		for _, t := range tests {
259			v := AssignVariant(userID.String(), t.Name, t.TrafficPct)
260			variantName := t.ControlVariant
261			if v == "test" {
262				variantName = t.TestVariant
263			}
264			parts = append(parts, t.Name+":"+variantName)
265		}
266		return strings.Join(parts, ",")
267	}
