26	func (s *CollectibleService) Create(ctx context.Context, req dto.CreateCollectibleRequest, sellerID uuid.UUID) (*model.Collectible, error) {
27		currency := req.Currency
28		if currency == "" {
29			currency = "USD"
30		}
31	
32		tokenID := req.TokenID
33		chainID := req.ChainID
34		hasToken := tokenID != ""
35		hasChain := chainID != 0
36		if req.ContractAddress != "" {
37			if !hasToken || !hasChain {
38				return nil, fmt.Errorf("%w: contract_address requires chain_id and token_id", dto.ErrValidation)
39			}
40		} else if hasToken || hasChain {
41			// When either identity field is provided, require both.
42			if !hasToken || !hasChain {
43				return nil, fmt.Errorf("%w: chain_id and token_id must both be provided when either is set", dto.ErrValidation)
44			}
45		} else {
46			// Neither provided — generate platform defaults for off-chain items.
47			tokenID = uuid.New().String()
48			chainID = 1
49		}
50	
51		c := &model.Collectible{
52			SellerID:        sellerID,
53			Title:           req.Title,
54			Description:     req.Description,
55			ContractAddress: req.ContractAddress,
56			ChainID:         chainID,
