1	// Unit tests for rolling-window login lockout policy.
2	// Mirrors constants and logic from backend/internal/service/auth_service.go.
3	import { describe, it, expect } from 'vitest';
4	
5	const MAX_USER_FAILURES = 5;
6	const MAX_IP_FAILURES   = 20;
7	const FAILURE_WINDOW_MS = 15 * 60 * 1000;  // 15 minutes
8	const LOCKOUT_MS        = 30 * 60 * 1000;  // 30 minutes
9	
10	function withinWindow(attemptTime, now = Date.now()) {
11	  return attemptTime > (now - FAILURE_WINDOW_MS);
12	}
13	
14	function countRecent(attempts, now = Date.now()) {
15	  return attempts.filter(a => withinWindow(a, now)).length;
16	}
17	
18	function shouldLockUser(attempts, now = Date.now()) {
19	  return countRecent(attempts, now) >= MAX_USER_FAILURES;
20	}
21	
22	function shouldLockIP(attempts, now = Date.now()) {
23	  return countRecent(attempts, now) >= MAX_IP_FAILURES;
24	}
25	
26	function isLockoutExpired(lockedUntil, now = Date.now()) {
27	  return now >= lockedUntil;
28	}
29	
30	describe('Rolling Window Threshold', () => {
31	  it('under threshold → no lock', () => {
32	    const now = Date.now();
33	    const attempts = Array.from({ length: 4 }, (_, i) => now - i * 60000);
34	    expect(shouldLockUser(attempts, now)).toBe(false);
35	  });
36	
37	  it('at threshold → locks', () => {
38	    const now = Date.now();
39	    const attempts = Array.from({ length: 5 }, (_, i) => now - i * 10000);
40	    expect(shouldLockUser(attempts, now)).toBe(true);
41	  });
42	
43	  it('above threshold → locks', () => {
44	    const now = Date.now();
45	    const attempts = Array.from({ length: 8 }, (_, i) => now - i * 5000);
46	    expect(shouldLockUser(attempts, now)).toBe(true);
47	  });
48	});
49	
50	describe('Window Expiry', () => {
51	  it('old attempts ignored', () => {
52	    const now = Date.now();
53	    const old = Array.from({ length: 10 }, (_, i) => now - (20 + i) * 60000);
54	    expect(shouldLockUser(old, now)).toBe(false);
55	  });
56	
57	  it('mix of old and recent under threshold', () => {
58	    const now = Date.now();
59	    const old = [now - 20 * 60000];
60	    const recent = Array.from({ length: 4 }, (_, i) => now - i * 60000);
61	    expect(shouldLockUser([...old, ...recent], now)).toBe(false);
62	  });
63	
64	  it('mix reaching threshold', () => {
65	    const now = Date.now();
66	    const old = [now - 20 * 60000];
