9	// FNV-1a 32-bit hash matching Go's hash/fnv
10	function fnv32a(buf) {
11	  const FNV_PRIME = 0x01000193;
12	  let h = 0x811C9DC5;
13	  for (let i = 0; i < buf.length; i++) {
