117	// parseFlexibleDate accepts datetime-local (2006-01-02T15:04), RFC3339, and US format.
118	func parseFlexibleDate(s string) (time.Time, error) {
119		formats := []string{
120			"2006-01-02T15:04",       // HTML datetime-local
121			time.RFC3339,             // Standard API format
122			"2006-01-02T15:04:05",   // ISO without timezone
123			"01/02/2006 3:04 PM",    // US human-readable
124		}
125		for _, f := range formats {
126			if t, err := time.Parse(f, s); err == nil {
127				return t, nil
128			}
129		}
130		return time.Time{}, fmt.Errorf("unrecognized date format: %s", s)
131	}
