133	// AssignVariant uses deterministic hashing: fnv32(userID + testName) % 100.
134	func AssignVariant(userID, testName string, trafficPct int) string {
135		h := fnv.New32a()
136		h.Write([]byte(userID + testName))
137		bucket := int(h.Sum32() % 100)
138		if bucket < trafficPct {
139			return "test"
140		}
141		return "control"
142	}
