3	// ExperimentComponent defines a registered UI component that supports A/B
4	// testing. Every experiment name must match an entry here, and variant names
5	// must be drawn from the component's allowed set.
6	type ExperimentComponent struct {
7		// Description is a human-readable summary shown in the admin UI.
8		Description string
9		// AllowedVariants maps variant name → short description.
10		// The map must contain at least two entries (control + test).
11		AllowedVariants map[string]string
12	}
13	
14	// ExperimentRegistry maps experiment names to the UI components they control.
15	// Adding a new A/B-testable component requires registering it here AND
16	// implementing the corresponding frontend branch.
17	var ExperimentRegistry = map[string]ExperimentComponent{
18		"catalog_layout": {
19			Description: "Controls the collectible catalog grid layout (CatalogPage.tsx)",
20			AllowedVariants: map[string]string{
21				"grid": "Multi-column responsive grid (default)",
22				"list": "Single-column list layout",
