27	// ValidateExperiment checks that the experiment name and both variant names
28	// are present in the registry. Returns an empty string on success, or a
29	// human-readable error message on failure.
30	func ValidateExperiment(name, controlVariant, testVariant string) string {
31		comp, ok := ExperimentRegistry[name]
32		if !ok {
33			allowed := make([]string, 0, len(ExperimentRegistry))
34			for k := range ExperimentRegistry {
35				allowed = append(allowed, k)
