function maskValue(value) {
  if (value.includes('@')) {
    const [local, domain] = value.split('@');
    const lastDot = domain.lastIndexOf('.');
    return local[0] + '***@' + domain[0] + '***' + domain.slice(lastDot);
  }
  if (value.length > 4) return '***' + value.slice(-4);
  return '***';
}
