10		"golang.org/x/time/rate"
11	)
12	
13	type RateLimiterConfig struct {
14		Rate  rate.Limit
15		Burst int
16		KeyFn func(c echo.Context) string
17	}
18	
19	type rateLimiterEntry struct {
20		limiter  *rate.Limiter
21		lastSeen time.Time
22	}
23	
24	type RateLimiter struct {
25		mu       sync.Mutex
26		limiters map[string]*rateLimiterEntry
27		config   RateLimiterConfig
28	}
29	
30	func NewRateLimiter(cfg RateLimiterConfig) *RateLimiter {
31		rl := &RateLimiter{
32			limiters: make(map[string]*rateLimiterEntry),
33			config:   cfg,
34		}
35		go rl.cleanup()
36		return rl
37	}
38	
39	func (rl *RateLimiter) getLimiter(key string) *rate.Limiter {
40		rl.mu.Lock()
41		defer rl.mu.Unlock()
42	
43		e, ok := rl.limiters[key]
44		if !ok {
45			limiter := rate.NewLimiter(rl.config.Rate, rl.config.Burst)
46			rl.limiters[key] = &rateLimiterEntry{limiter: limiter, lastSeen: time.Now()}
47			return limiter
48		}
49		e.lastSeen = time.Now()
50		return e.limiter
51	}
52	
53	func (rl *RateLimiter) cleanup() {
54		ticker := time.NewTicker(10 * time.Minute)
55		defer ticker.Stop()
56		for range ticker.C {
57			rl.mu.Lock()
58			cutoff := time.Now().Add(-1 * time.Hour)
59			for k, e := range rl.limiters {
60				if e.lastSeen.Before(cutoff) {
61					delete(rl.limiters, k)
62				}
63			}
64			rl.mu.Unlock()
65		}
66	}
67	
68	func (rl *RateLimiter) Middleware() echo.MiddlewareFunc {
69		return func(next echo.HandlerFunc) echo.HandlerFunc {
70			return func(c echo.Context) error {
71				key := rl.config.KeyFn(c)
72				limiter := rl.getLimiter(key)
73	
74				if !limiter.Allow() {
75					c.Response().Header().Set("Retry-After", "60")
76					return echo.NewHTTPError(http.StatusTooManyRequests, dto.ErrorResponse{
77						Error: dto.ErrorDetail{
78							Code:      dto.CodeRateLimited,
79							Message:   "too many requests",
80							RequestID: GetRequestID(c),
81						},
82					})
83				}
84				return next(c)
85			}
86		}
87	}
88	
