90	
91	func LoginRateLimiter() *RateLimiter {
92		// 10 requests per 15 minutes per IP
93		return NewRateLimiter(RateLimiterConfig{
94			Rate:  rate.Every(90 * time.Second), // ~10 per 15 min
95			Burst: 10,
96			KeyFn: func(c echo.Context) string { return "login:" + c.RealIP() },
97		})
98	}
99	
100	func OrderRateLimiter() *RateLimiter {
101		// 30 per minute per user
102		return NewRateLimiter(RateLimiterConfig{
103			Rate:  rate.Every(2 * time.Second),
104			Burst: 30,
105			KeyFn: func(c echo.Context) string { return "order:" + GetUserID(c) },
106		})
107	}
108	
109	func OrderIPRateLimiter() *RateLimiter {
110		// 60 per minute per IP — catches credential-stuffing bots that rotate users.
111		return NewRateLimiter(RateLimiterConfig{
112			Rate:  rate.Every(1 * time.Second),
113			Burst: 60,
114			KeyFn: func(c echo.Context) string { return "order_ip:" + c.RealIP() },
115		})
116	}
117	
118	func MessageRateLimiter() *RateLimiter {
119		// 20 per minute per user
120		return NewRateLimiter(RateLimiterConfig{
121			Rate:  rate.Every(3 * time.Second),
122			Burst: 20,
123			KeyFn: func(c echo.Context) string { return "message:" + GetUserID(c) },
124		})
125	}
126	
127	func MessageIPRateLimiter() *RateLimiter {
128		// 40 per minute per IP — prevents spam from a single network.
129		return NewRateLimiter(RateLimiterConfig{
130			Rate:  rate.Every(1500 * time.Millisecond),
131			Burst: 40,
132			KeyFn: func(c echo.Context) string { return "message_ip:" + c.RealIP() },
133		})
134	}
135	
136	func ListingRateLimiter() *RateLimiter {
137		// 10 per hour per user
138		return NewRateLimiter(RateLimiterConfig{
139			Rate:  rate.Every(6 * time.Minute),
140			Burst: 10,
141			KeyFn: func(c echo.Context) string { return "listing:" + GetUserID(c) },
142		})
143	}
