  it('pending → failed',                     () => expect(TRANSITIONS.pending.has('failed')).toBe(true));
  it('pending cannot skip to perm_failed',   () => expect(TRANSITIONS.pending.has('permanently_failed')).toBe(false));
  it('failed → delivered on retry',          () => expect(TRANSITIONS.failed.has('delivered')).toBe(true));
  it('failed → permanently_failed',          () => expect(TRANSITIONS.failed.has('permanently_failed')).toBe(true));
  it('delivered is terminal',                () => expect(TRANSITIONS.delivered.size).toBe(0));
