  const WORKFLOW_EVENTS = new Set(['refund_approved', 'arbitration_opened', 'review_posted']);

  it('funnel views include all view types', () => expect(VIEW_EVENTS).toEqual(new Set(['item_view', 'catalog_view', 'view'])));
  it('funnel orders event',   () => expect(ORDER_EVENTS.has('order_created')).toBe(true));
  it('checkout_failed exists', () => expect(FAILURE_EVENTS.has('checkout_failed')).toBe(true));
  it('anomaly detector uses checkout_failed', () => {
    const emitted = 'checkout_failed';
    const queried = 'checkout_failed';
    expect(emitted).toBe(queried);
  });
  it('refund_approved event tracked',       () => expect(WORKFLOW_EVENTS.has('refund_approved')).toBe(true));
  it('arbitration_opened event tracked',    () => expect(WORKFLOW_EVENTS.has('arbitration_opened')).toBe(true));
  it('review_posted event tracked',         () => expect(WORKFLOW_EVENTS.has('review_posted')).toBe(true));
});

// Dashboard
describe('Dashboard Metrics', () => {
  it('owned_collectibles counts completed orders by buyer', () => {
    const query = "SELECT COUNT(*) FROM orders WHERE buyer_id = $1 AND status = 'completed'";
    expect(query).toContain('buyer_id');
    expect(query).toContain('completed');
    expect(query).not.toContain('seller_id');
  });
});
"}

